import{_ as o,o as t,c,ag as i}from"./chunks/framework.DAvaMl8U.js";const h=JSON.parse('{"title":"Core: Connectors (Plugin Layer)","description":"","frontmatter":{},"headers":[],"relativePath":"core-connectors.md","filePath":"core-connectors.md"}'),r={name:"core-connectors.md"};function a(n,e,l,d,s,p){return t(),c("div",null,[...e[0]||(e[0]=[i('<h1 id="core-connectors-plugin-layer" tabindex="-1">Core: Connectors (Plugin Layer) <a class="header-anchor" href="#core-connectors-plugin-layer" aria-label="Permalink to &quot;Core: Connectors (Plugin Layer)&quot;">​</a></h1><p>The connector layer is a provider-based plugin system.</p><p>Source modules:</p><ul><li><code>backend/src/connectors/plugin-types.ts</code></li><li><code>backend/src/connectors/registry.ts</code></li><li><code>backend/src/connectors/google-drive.ts</code></li><li><code>backend/src/connectors/notion.ts</code></li><li><code>backend/src/connectors/slack.ts</code></li></ul><hr><h2 id="provider-contract" tabindex="-1">Provider contract <a class="header-anchor" href="#provider-contract" aria-label="Permalink to &quot;Provider contract&quot;">​</a></h2><p>Each provider registers three parts:</p><ol><li><code>manifest</code><ul><li>Connector metadata and retry policy</li><li>Capability flags</li></ul></li><li><code>plugin</code><ul><li><code>validateConfig(...)</code></li><li><code>enumerate(...)</code></li><li><code>fetchDocument(...)</code></li></ul></li><li><code>auth</code><ul><li><code>authorizeUrl(state)</code></li><li><code>exchangeCode(code, redirectUri)</code></li><li>optional <code>refreshCredentials(credentials)</code></li></ul></li></ol><p>This contract is typed by <code>ConnectorProvider</code> in <code>plugin-types.ts</code>.</p><hr><h2 id="manifest-responsibilities" tabindex="-1">Manifest responsibilities <a class="header-anchor" href="#manifest-responsibilities" aria-label="Permalink to &quot;Manifest responsibilities&quot;">​</a></h2><p><code>ConnectorManifest</code> defines stable behavior expected by orchestration:</p><ul><li><code>key</code>, <code>displayName</code>, <code>authType</code></li><li><code>supportsIncremental</code>, <code>supportsAcl</code></li><li><code>supportedContentTypes</code>, <code>maxPageSize</code></li><li><code>retryPolicy</code>: <code>{ maxAttempts, backoffMs, strategy }</code></li><li>optional capability flags under <code>capabilities</code></li></ul><p>The worker uses manifest retry policy directly when enqueuing <code>sync-document</code> jobs.</p><hr><h2 id="data-boundaries" tabindex="-1">Data boundaries <a class="header-anchor" href="#data-boundaries" aria-label="Permalink to &quot;Data boundaries&quot;">​</a></h2><p>Connector output is split into two typed parts:</p><ul><li><code>ConnectorDocumentRef</code> from <code>enumerate(...)</code><ul><li>Stable metadata and source identity</li><li>Includes <code>sourcePermissions</code> and <code>metadata</code></li></ul></li><li><code>ConnectorFetchedDocument</code> from <code>fetchDocument(...)</code><ul><li>Primary text payload (<code>content</code>)</li><li>Optional content-type/path/permissions enrichment</li></ul></li></ul><p>These two outputs are transformed into one canonical envelope by the orchestration layer.</p><hr><h2 id="registry-behavior" tabindex="-1">Registry behavior <a class="header-anchor" href="#registry-behavior" aria-label="Permalink to &quot;Registry behavior&quot;">​</a></h2><p><code>registry.ts</code> is the single source of truth:</p><ul><li><code>registerConnectorProvider(provider)</code></li><li><code>getConnectorProvider(kind)</code></li><li><code>loadConnectors()</code> for provider side-effect registration</li></ul><p>No legacy connector base class path remains.</p>',24)])])}const m=o(r,[["render",a]]);export{h as __pageData,m as default};
